SELECT
  CASE
    WHEN (riskdata2025.rebillNumber = 0 AND riskdata2025.termIso IN ('OT', 'P26D', 'P2M', 'P3M', 'P19D', 'P27D', 'P0Y', 'P7D', 'P30D', 'P1M') AND riskdata2025.action = 'setup' AND riskdata2025.productGroupType = '1') OR (riskdata2025.rebillNumber = 0 AND riskdata2025.termIso IN ('OT', 'P26D', 'P2M', 'P3M', 'P19D', 'P27D', 'P0Y', 'P7D', 'P30D', 'P1M') AND riskdata2025.recordType = 'refund' AND riskdata2025.productGroupType = '1') THEN 'Monthly Initial'
    WHEN (riskdata2025.rebillNumber <> 0 AND riskdata2025.termIso IN ('OT', 'P26D', 'P2M', 'P3M', 'P19D', 'P27D', 'P0Y', 'P7D', 'P30D', 'P1M') AND riskdata2025.action = 'renew' AND riskdata2025.productGroupType = '1') OR (riskdata2025.rebillNumber <> 0 AND riskdata2025.termIso IN ('OT', 'P26D', 'P2M', 'P3M', 'P19D', 'P27D', 'P0Y', 'P7D', 'P30D', 'P1M') AND riskdata2025.recordType = 'refund' AND riskdata2025.productGroupType = '1') THEN 'Monthly Renewal'
    WHEN (riskdata2025.action = 'setup' AND riskdata2025.productGroupType = '2') OR (riskdata2025.rebillNumber = 0 AND riskdata2025.productGroupType = '2' AND riskdata2025.recordType = 'refund') THEN 'Addon Sale'
    WHEN (riskdata2025.action = 'renew' AND riskdata2025.productGroupType = '2') OR (riskdata2025.rebillNumber <> 0 AND riskdata2025.productGroupType = '2' AND riskdata2025.recordType = 'refund') THEN 'Addon Renewal'
    WHEN (riskdata2025.productGroupType = '1' AND riskdata2025.termIso IN ('P1Y', 'P12M', 'P2Y', 'P5Y', 'P24M') AND riskdata2025.action = 'setup') OR (riskdata2025.productGroupType = '1' AND riskdata2025.termIso IN ('P1Y', 'P12M', 'P2Y', 'P5Y', 'P24M') AND riskdata2025.rebillNumber = 0 AND riskdata2025.recordType = 'refund') THEN 'Annual Sub Sale'
    WHEN (riskdata2025.productGroupType = '1' AND riskdata2025.termIso IN ('P1Y', 'P12M', 'P2Y', 'P5Y', 'P24M') AND riskdata2025.action = 'renew') OR (riskdata2025.productGroupType = '1' AND riskdata2025.termIso IN ('P1Y', 'P12M', 'P2Y', 'P5Y', 'P24M') AND riskdata2025.rebillNumber <> 0) THEN 'Annual Sub Renewal'
    WHEN riskdata2025.termIso = 'P6M' THEN 'P6M Renewals' WHEN riskdata2025.termIso <> 'P6M' AND riskdata2025.action = 'upgraded' THEN 'Upgrades' ELSE 'Other'
  END AS risk_defined_subscription_product_type,
  CASE WHEN (CASE WHEN riskdata2025.cardTypeN LIKE '%nyce%' THEN 'nyce' WHEN riskdata2025.cardTypeN LIKE '%pulse%' THEN 'pulse' WHEN riskdata2025.cardTypeN LIKE '%accel%' THEN 'accel' WHEN riskdata2025.cardTypeN LIKE '%star%' THEN 'star' WHEN riskdata2025.cardTypeN LIKE '%mc_google_pay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%mc_applepay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%maestro_usa%' THEN 'mastercard' ELSE riskdata2025.accountType END) LIKE '%maestro%' THEN 'mastercard' WHEN (CASE WHEN riskdata2025.cardTypeN LIKE '%nyce%' THEN 'nyce' WHEN riskdata2025.cardTypeN LIKE '%pulse%' THEN 'pulse' WHEN riskdata2025.cardTypeN LIKE '%accel%' THEN 'accel' WHEN riskdata2025.cardTypeN LIKE '%star%' THEN 'star' WHEN riskdata2025.cardTypeN LIKE '%mc_google_pay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%mc_applepay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%maestro_usa%' THEN 'mastercard' ELSE riskdata2025.accountType END) LIKE '%master_card%' THEN 'mastercard' WHEN (CASE WHEN riskdata2025.cardTypeN LIKE '%nyce%' THEN 'nyce' WHEN riskdata2025.cardTypeN LIKE '%pulse%' THEN 'pulse' WHEN riskdata2025.cardTypeN LIKE '%accel%' THEN 'accel' WHEN riskdata2025.cardTypeN LIKE '%star%' THEN 'star' WHEN riskdata2025.cardTypeN LIKE '%mc_google_pay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%mc_applepay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%maestro_usa%' THEN 'mastercard' ELSE riskdata2025.accountType END) IS NULL OR (CASE WHEN riskdata2025.cardTypeN LIKE '%nyce%' THEN 'nyce' WHEN riskdata2025.cardTypeN LIKE '%pulse%' THEN 'pulse' WHEN riskdata2025.cardTypeN LIKE '%accel%' THEN 'accel' WHEN riskdata2025.cardTypeN LIKE '%star%' THEN 'star' WHEN riskdata2025.cardTypeN LIKE '%mc_google_pay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%mc_applepay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%maestro_usa%' THEN 'mastercard' ELSE riskdata2025.accountType END) LIKE '%unknown%' THEN 'unknown' WHEN (CASE WHEN riskdata2025.cardTypeN LIKE '%nyce%' THEN 'nyce' WHEN riskdata2025.cardTypeN LIKE '%pulse%' THEN 'pulse' WHEN riskdata2025.cardTypeN LIKE '%accel%' THEN 'accel' WHEN riskdata2025.cardTypeN LIKE '%star%' THEN 'star' WHEN riskdata2025.cardTypeN LIKE '%mc_google_pay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%mc_applepay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%maestro_usa%' THEN 'mastercard' ELSE riskdata2025.accountType END) LIKE '%american%' AND (CASE WHEN riskdata2025.cardTypeN LIKE '%nyce%' THEN 'nyce' WHEN riskdata2025.cardTypeN LIKE '%pulse%' THEN 'pulse' WHEN riskdata2025.cardTypeN LIKE '%accel%' THEN 'accel' WHEN riskdata2025.cardTypeN LIKE '%star%' THEN 'star' WHEN riskdata2025.cardTypeN LIKE '%mc_google_pay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%mc_applepay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%maestro_usa%' THEN 'mastercard' ELSE riskdata2025.accountType END) LIKE '%express%' THEN 'american express' ELSE (CASE WHEN riskdata2025.cardTypeN LIKE '%nyce%' THEN 'nyce' WHEN riskdata2025.cardTypeN LIKE '%pulse%' THEN 'pulse' WHEN riskdata2025.cardTypeN LIKE '%accel%' THEN 'accel' WHEN riskdata2025.cardTypeN LIKE '%star%' THEN 'star' WHEN riskdata2025.cardTypeN LIKE '%mc_google_pay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%mc_applepay%' THEN 'mastercard' WHEN riskdata2025.cardTypeN LIKE '%maestro_usa%' THEN 'mastercard' ELSE riskdata2025.accountType END) END AS account_type,
  COALESCE(riskdata2025.bin, 'unallocated') AS bin,
  CASE WHEN riskdata2025.Company LIKE '%TotalAV%' THEN 'TotalAV' WHEN riskdata2025.Company LIKE '%Total Adblock%' THEN 'Total Adblock' WHEN riskdata2025.Company LIKE '%Total Drive%' THEN 'Total Drive' WHEN riskdata2025.Company LIKE '%Total VPN%' THEN 'Total VPN' WHEN riskdata2025.Company LIKE '%Total Cleaner%' THEN 'Total Cleaner' ELSE 'Other Brands' END AS company,
  riskdata2025.currency AS currency,
  riskdata2025.gatewayFid AS gateway_fid,
  CASE WHEN riskdata2025.paymentMethodProvider LIKE '%GOOGLE%' THEN 'GOOGLEPAY' WHEN riskdata2025.paymentMethodProvider LIKE '%APPLE%' THEN 'APPLEPAY' ELSE 'non_gp_ap' END AS paymentMethodProvider,

  CASE
  WHEN riskdata2025.Company != 'Total Drive' AND cast(chive.renewal_number_1 as string) in ('1','2','3') then 'sticky'
  WHEN riskdata2025.Company != 'Total Drive' AND cast(chive.renewal_number_1 as string) not in ('1','2','3') THEN 'non_sticky'
  ELSE 'non_sticky' END AS renewal_number,

  -- 🟢 UPGRADE: FCP Logic injected via Chive JOIN
  case when ftran.fcpNumber != 1 then '2+' else '1' end as fcpNumber,
  case when ftran.attemptNumber != 1 then '2+' else '1' end as attemptNumber,
  case when chive.bank_country_0 in ('US', 'USA') then 'USA' else 'Non-USA' end as country,

  COUNT(DISTINCT CASE WHEN riskdata2025.recordType = 'transaction' THEN riskdata2025.gatewayTransactionId ELSE NULL END) AS trx_count
FROM `sapient-tangent-172609.Risk_Data.risk-data-bc-test` AS riskdata2025

LEFT JOIN (select gatewayTransactionId, fcpNumber, attemptNumber from `sapient-tangent-172609.fortifi_views.reporting_finance_transactions_last_365_days` QUALIFY ROW_NUMBER() OVER(PARTITION BY gatewayTransactionId ORDER BY date ASC) = 1) as ftran ON CAST(ftran.gatewayTransactionId AS STRING) = CAST(riskdata2025.gatewayTransactionId AS STRING)
LEFT JOIN (select connector_transaction_id_0, bank_country_0, renewal_number_1 from `chive-data-1985.ws_39d_9B2SQQ1f1l.TRAN47f28cde`QUALIFY ROW_NUMBER() OVER(PARTITION BY connector_transaction_id_0 ORDER BY date ASC) = 1) AS chive ON CAST(chive.connector_transaction_id_0 AS STRING) = CAST(riskdata2025.gatewayTransactionId AS STRING)

WHERE CAST(riskdata2025.recordDate AS TIMESTAMP) >= '{ACTUALS_START_DATE}'  
AND CAST(riskdata2025.recordDate AS TIMESTAMP) < '{ACTUALS_END_DATE}'

GROUP BY ALL